Here are the public test cases for feature10_async_members:
{
  "description": "Suspending (asynchronous) members are supported on equal footing with ordinary members: they can be programmed with a fixed value or a computed answer, and their invocation count can be verified.",
  "cases": [
    {
      "input": {
        "async": {
          "returns": 42
        }
      },
      "expected_output": "value=42\n"
    },
    {
      "input": {
        "async": {
          "verify": true,
          "invocations": 2
        }
      },
      "expected_output": "verified member=asyncNumber times=2\n"
    }
  ]
}

Here are the public test cases for feature11_1_named_double:
{
  "description": "A test double can be created with a custom name. The name appears in diagnostic output, so an unmet verification on a named double reports the configured name as the target's prefix.",
  "cases": [
    {
      "input": {
        "double": "mock",
        "settings": {
          "name": "myDouble"
        },
        "script": [
          {
            "do": "verify",
            "member": "text",
            "mode": {
              "times": 1
            }
          }
        ]
      },
      "expected_output": "error=wanted_but_not_invoked target=myDouble.text()\n"
    }
  ]
}

Here are the public test cases for feature11_2_default_answers:
{
  "description": "A test double can be configured with an alternative default-answer strategy for unprogrammed members: return the double itself where the return type allows it, return freshly created doubles for reference-typed members, or resolve a chain of members lazily through deep stubbing.",
  "cases": [
    {
      "input": {
        "double": "mock",
        "settings": {
          "default_answer": "returns_self"
        },
        "script": [
          {
            "do": "invoke",
            "member": "selfChain"
          }
        ]
      },
      "expected_output": "identity=self\n"
    },
    {
      "input": {
        "double": "mock",
        "settings": {
          "default_answer": "returns_mocks"
        },
        "script": [
          {
            "do": "invoke",
            "member": "extra"
          }
        ]
      },
      "expected_output": "presence=present\n"
    },
    {
      "input": {
        "double": "mock",
        "settings": {
          "default_answer": "deep_stubs"
        },
        "stubs": [
          {
            "member": "deepChain",
            "return": 7
          }
        ],
        "script": [
          {
            "do": "invoke",
            "member": "deepChain"
          }
        ]
      },
      "expected_output": "value=7\n"
    }
  ]
}

Here are the public test cases for feature11_3_serializable_marker:
{
  "description": "A test double can be marked serializable at creation time. A double created with the serializable option reports as serializable, whereas an ordinary double does not.",
  "cases": [
    {
      "input": {
        "double": "mock",
        "settings": {
          "serializable": true
        },
        "script": [
          {
            "do": "report_serializable"
          }
        ]
      },
      "expected_output": "serializable=true\n"
    },
    {
      "input": {
        "double": "mock",
        "script": [
          {
            "do": "report_serializable"
          }
        ]
      },
      "expected_output": "serializable=false\n"
    }
  ]
}

Here are the public test cases for feature11_4_stub_only_enforcement:
{
  "description": "A test double can be created as stub-only, which records no invocation history to save memory. Programmed responses still work, but attempting to verify invocations on a stub-only double is rejected.",
  "cases": [
    {
      "input": {
        "double": "mock",
        "settings": {
          "stub_only": true
        },
        "stubs": [
          {
            "member": "text",
            "return": "S"
          }
        ],
        "script": [
          {
            "do": "invoke",
            "member": "text"
          }
        ]
      },
      "expected_output": "value=S\n"
    },
    {
      "input": {
        "double": "mock",
        "settings": {
          "stub_only": true
        },
        "script": [
          {
            "do": "invoke",
            "member": "acceptNumber",
            "arg": 1
          },
          {
            "do": "verify",
            "member": "acceptNumber",
            "matcher": {
              "any": true
            },
            "mode": {
              "times": 1
            }
          }
        ]
      },
      "expected_output": "error=stub_only member=acceptNumber times=1\n"
    }
  ]
}

Here are the public test cases for feature11_5_invocation_listener:
{
  "description": "A test double can be created with an invocation listener that is notified whenever any member is invoked. After exercising the double, the listener reports that it was notified; without any invocation it reports that it was not.",
  "cases": [
    {
      "input": {
        "double": "mock",
        "settings": {
          "invocation_listener": true
        },
        "script": [
          {
            "do": "invoke",
            "member": "acceptNumber",
            "arg": 1
          },
          {
            "do": "report_listener"
          }
        ]
      },
      "expected_output": "listener_notified=true\n"
    },
    {
      "input": {
        "double": "mock",
        "settings": {
          "invocation_listener": true
        },
        "script": [
          {
            "do": "report_listener"
          }
        ]
      },
      "expected_output": "listener_notified=false\n"
    }
  ]
}

Here are the public test cases for feature11_6_construction_failure:
{
