        "script": [
          {
            "do": "invoke",
            "member": "text"
          },
          {
            "do": "invoke",
            "member": "text"
          },
          {
            "do": "invoke",
            "member": "text"
          }
        ]
      },
      "expected_output": "value=a\nvalue=b\nvalue=b\n"
    },
    {
      "input": {
        "double": "mock",
        "stubs": [
          {
            "member": "number",
            "return_consecutively": [
              1,
              2,
              3
            ]
          }
        ],
        "script": [
          {
            "do": "invoke",
            "member": "number"
          },
          {
            "do": "invoke",
            "member": "number"
          },
          {
            "do": "invoke",
            "member": "number"
          },
          {
            "do": "invoke",
            "member": "number"
          }
        ]
      },
      "expected_output": "value=1\nvalue=2\nvalue=3\nvalue=3\n"
    }
  ]
}

Here are the public test cases for feature2_3_stub_override:
{
  "description": "Programming a member that already has a configured response replaces the earlier response: the most recently programmed value wins for subsequent invocations.",
  "cases": [
