          {
            "do": "verify",
            "member": "varargs"
          }
        ]
      },
      "expected_output": "value=false\nverified member=varargs times=1\n"
    },
    {
      "input": {
        "double": "mock",
        "script": [
          {
            "do": "invoke",
            "member": "stringArrayArg",
            "args": [
              "a",
              "b"
            ]
          },
          {
            "do": "verify",
            "member": "stringArrayArg",
            "args": [
              "a",
              "b"
            ]
          }
        ]
      },
      "expected_output": "verified member=stringArrayArg times=1\n"
    },
    {
      "input": {
        "double": "mock",
        "script": [
